    // ---------------------------------------------------------------------------
    // SseChoice — finish_reason deserialization
    // ---------------------------------------------------------------------------

    #[test]
    fn sse_choice_deserializes_with_finish_reason() {
        let json = r#"{"delta":{"content":"hello"},"finish_reason":"stop"}"#;
        let choice: SseChoice = serde_json::from_str(json).unwrap();
        assert!(choice.finish_reason.is_some());
        assert_eq!(choice.finish_reason.as_deref(), Some("stop"));
        assert!(choice.delta.is_some());
    }

    #[test]
    fn sse_choice_deserializes_without_finish_reason() {
        let json = r#"{"delta":{"content":"hello"}}"#;
        let choice: SseChoice = serde_json::from_str(json).unwrap();
        assert!(choice.finish_reason.is_none());
        assert!(choice.delta.is_some());
    }

    #[test]
    fn sse_choice_empty_defaults() {
        let json = r"{}";
        let choice: SseChoice = serde_json::from_str(json).unwrap();
        assert!(choice.finish_reason.is_none());
        assert!(choice.delta.is_none());
    }

    // ---------------------------------------------------------------------------
